import React, { useState, useEffect, useRef } from 'react';
import { Typography } from '@mui/material';
import * as d3 from 'd3';
import axios from 'axios';

function AliToSherazi({ user }) {
  const svgRef = useRef(null);
  const [chain, setChain] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await axios.get('/api/ali-sherazia');
        // Sirf 3 nodes filter karein
        const filtered = res.data.filter(node => 
          node.name.includes('Ali ibn Abi Talib') ||
          node.name.includes('Hasan') ||
          node.name.includes('Hussain')
        );
        setChain(filtered);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  useEffect(() => {
    if (chain.length === 0) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll('*').remove();

    const ali = chain.find(n => n.name.includes('Ali ibn Abi Talib'));
    const hasan = chain.find(n => n.name.includes('Hasan'));
    const hussain = chain.find(n => n.name.includes('Hussain'));

    if (!ali) return;

    // ─── LAYOUT ───
    const boxW = 300, boxH = 200;
    const gapY = 100;
    const pad = 60;

    const aliX = 200, aliY = 80;
    const hasanX = aliX - boxW - 50;
    const hussainX = aliX + boxW + 50;
    const childY = aliY + boxH + gapY;

    const totalWidth = 2 * boxW + 50 + 2 * pad;
    const totalHeight = childY + boxH + pad;

    svg.attr('width', totalWidth).attr('height', totalHeight)
      .attr('viewBox', `0 0 ${totalWidth} ${totalHeight}`);

    // ─── DEFS (Shadow) ───
    const defs = svg.append('defs');
    defs.append('filter')
      .attr('id', 'shadow')
      .append('feDropShadow')
      .attr('dx', 0).attr('dy', 4).attr('stdDeviation', 6)
      .attr('flood-color', '#000')
      .attr('flood-opacity', 0.15);

    // ─── MAIN GROUP ───
    const mainGroup = svg.append('g');

    // ─── CONNECTORS (Curved) ───
    const lineColor = '#2E7D32';
    const lineWidth = 3;

    // Ali → Hasan
    mainGroup.append('path')
      .attr('fill', 'none')
      .attr('stroke', lineColor)
      .attr('stroke-width', lineWidth)
      .attr('d', `M${aliX + boxW/2},${aliY + boxH} C${aliX + boxW/2},${aliY + boxH + 60} ${hasanX + boxW/2},${childY - 60} ${hasanX + boxW/2},${childY}`);

    // Ali → Hussain
    mainGroup.append('path')
      .attr('fill', 'none')
      .attr('stroke', lineColor)
      .attr('stroke-width', lineWidth)
      .attr('d', `M${aliX + boxW/2},${aliY + boxH} C${aliX + boxW/2},${aliY + boxH + 60} ${hussainX + boxW/2},${childY - 60} ${hussainX + boxW/2},${childY}`);

    // ─── DRAW NODES ───
    const drawNode = (x, y, node, isAli = false) => {
      const g = mainGroup.append('g').attr('transform', `translate(${x}, ${y})`);

      // Box with shadow
      g.append('rect')
        .attr('width', boxW).attr('height', boxH)
        .attr('rx', 16).attr('ry', 16)
        .attr('fill', '#ffffff')
        .attr('stroke', isAli ? '#D4AF37' : '#2E7D32')
        .attr('stroke-width', isAli ? 4 : 2.5)
        .attr('filter', 'url(#shadow)');

      // Top accent bar
      g.append('rect')
        .attr('width', boxW).attr('height', isAli ? 8 : 6)
        .attr('rx', 4).attr('ry', 4)
        .attr('fill', isAli ? '#D4AF37' : '#2E7D32');

      // Crown for Ali
      if (isAli) {
        g.append('text')
          .attr('x', boxW - 30).attr('y', 30)
          .attr('font-size', '24px')
          .attr('text-anchor', 'middle')
          .text('👑');
      }

      // Content
      const father = node.father_name || '';
      const fatherLine = father ? `bin ${father}` : '';

      g.append('foreignObject')
        .attr('width', boxW - 40).attr('height', boxH - 80)
        .attr('x', 20).attr('y', 20)
        .append('xhtml:div')
        .style('width', '100%').style('height', '100%')
        .style('display', 'flex').style('flex-direction', 'column')
        .style('align-items', 'center').style('justify-content', 'center')
        .style('text-align', 'center')
        .style('font-size', '16px')
        .style('line-height', '1.4')
        .html(`
          <div style="font-size:18px;font-weight:bold;color:#1B5E20;">${node.name}</div>
          ${father ? `<div style="font-size:14px;color:#1565C0;margin-top:4px;">${fatherLine}</div>` : ''}
          ${node.wife_name ? `<div style="font-size:14px;color:#C2185B;margin-top:4px;">💍 ${node.wife_name}</div>` : ''}
          <div style="font-size:13px;color:#555;margin-top:6px;">Gen: <span style="font-weight:bold;">${node.generation_number}</span></div>
          ${node.info ? `<div style="font-size:13px;color:#777;margin-top:4px;">${node.info}</div>` : ''}
        `);
    };

    if (ali) drawNode(aliX, aliY, ali, true);
    if (hasan) drawNode(hasanX, childY, hasan);
    if (hussain) drawNode(hussainX, childY, hussain);

  }, [chain]);

  if (loading) return <Typography sx={{ textAlign: 'center', mt: 4 }}>Loading...</Typography>;

  return (
    <div style={{ width: '100%', height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      <Typography variant="h4" align="center" sx={{ mt: 3, mb: 2, color: '#1B5E20', fontWeight: 'bold', fontFamily: 'Noto Nastaliq Urdu, serif' }}>
        سلسلہ: حضرت علی (ع) تا حضرت حسین (ع)
      </Typography>
      <div style={{ flex: 1, padding: '20px', overflow: 'auto', background: '#f5f5f5' }}>
        <svg ref={svgRef} style={{ display: 'block', width: '100%', minHeight: '100%' }} />
      </div>
    </div>
  );
}

export default AliToSherazi;
